window.exeSearchData = {"page-mopyqj12-9x8j6fusc":{"name":"Página nueva","isIndex":true,"fileName":"index.html","fileUrl":"index.html","prePageId":null,"nextPageId":null,"blocks":{"20260502214002TABJLI":{"name":"Ecomensajeros: Nuestra Guía Interactiva.","order":1,"idevices":{"2026050220003916130Z":{"order":1,"htmlView":"<div class=\"exe-text-template\"><div class=\"textIdeviceContent\">\n            <div class=\"exe-text-activity\">\n                <div><p><img src=\"{{context_path}}/content/resources/2026050220003916130Z/1.png\" width=\"1024\" height=\"768\" alt=\"\"></p><p class=\"clearfix\"></p></div>\n            </div></div></div>","jsonProperties":"{\"ideviceId\":\"2026050220003916130Z\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p><img src=\\\"{{context_path}}/content/resources/2026050220003916130Z/1.png\\\" width=\\\"1024\\\" height=\\\"768\\\" alt=\\\"\\\" /></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"20260502214002DALXFM":{"name":"PRESENTACIÓN DE LA SdA.","order":2,"idevices":{"20260502201704919XDC":{"order":1,"htmlView":"<div class=\"exe-text-template\"><div class=\"textIdeviceContent\">\n            <div class=\"exe-text-activity\">\n                <div><p>¡Bienvenidos Ecomensajeros!</p>\n<p>En esta SdA que vamos a llevar a cabo, el alumnado dejará de ser un mero espectador para investigar los ecosistemas más cercanos de nuestra comunidad autónoma y transformar esa información en un producto digital y atractivo.</p>\n<p>El objetivo es que entiendan que la tecnología es una ventana para mostrar al mundo lo aprendido y una herramienta fundamental para proteger el entorno natural.</p><p class=\"clearfix\"></p></div>\n            </div></div></div>","jsonProperties":"{\"ideviceId\":\"20260502201704919XDC\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>¡Bienvenidos Ecomensajeros!</p>\\n<p>En esta SdA que vamos a llevar a cabo, el alumnado dejará de ser un mero espectador para investigar los ecosistemas más cercanos de nuestra comunidad autónoma y transformar esa información en un producto digital y atractivo.</p>\\n<p>El objetivo es que entiendan que la tecnología es una ventana para mostrar al mundo lo aprendido y una herramienta fundamental para proteger el entorno natural.</p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"20260502214002VIZTBX":{"name":"FICHA TÉCNICA.","order":3,"idevices":{"20260502202323529D7R":{"order":1,"htmlView":"<div class=\"exe-text-template\"><div class=\"textIdeviceContent\">\n            <div class=\"exe-text-activity\">\n                <div><p><img src=\"{{context_path}}/content/resources/20260502202323529D7R/2.png\" width=\"1024\" height=\"768\" alt=\"\"><br></p><p class=\"clearfix\"></p></div>\n            </div></div></div>","jsonProperties":"{\"ideviceId\":\"20260502202323529D7R\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p><img src=\\\"{{context_path}}/content/resources/20260502202323529D7R/2.png\\\" width=\\\"1024\\\" height=\\\"768\\\" alt=\\\"\\\" /><br /></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"20260502214002IAHOXE":{"name":"¿Qué vamos a aprender?","order":4,"idevices":{"20260502203000890DGS":{"order":1,"htmlView":"<div class=\"exe-text-template\"><div class=\"textIdeviceContent\">\n            <div class=\"exe-text-activity\">\n                <div><p><br></p>\n<p>Seleccionar y sintetizar información sobre flora, fauna y conservación.</p>\n<p>Utilizar Canva para comunicar ideas de forma visual.</p>\n<p>Trabajar de forma cooperativa y respetuosa.</p>\n<p>Crear una infografía interactiva con código QR para una exposición virtual en el colegio.</p><p class=\"clearfix\"></p></div>\n            </div></div></div>","jsonProperties":"{\"ideviceId\":\"20260502203000890DGS\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p><br /></p>\\n<p>Seleccionar y sintetizar información sobre flora, fauna y conservación.</p>\\n<p>Utilizar Canva para comunicar ideas de forma visual.</p>\\n<p>Trabajar de forma cooperativa y respetuosa.</p>\\n<p>Crear una infografía interactiva con código QR para una exposición virtual en el colegio.</p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"20260502214002JTLYMQ":{"name":"NUESTRA IDENTIDAD Y SEGURIDAD DIGITAL","order":5,"idevices":{"20260502203829207VJ7":{"order":1,"htmlView":"<div class=\"exe-text-template\"><div class=\"textIdeviceContent\">\n            <div class=\"exe-text-activity\">\n                <div><p>\"Para ser un buen Ecomensajero, primero debemos saber navegar seguros\"</p>\n<p><a href=\"{{context_path}}/content/resources/20260502203829207VJ7/GUIA_DEL_ECOMENSAJERO_SEGURO_2.pdf\" title=\"GUIA_DEL_ECOMENSAJERO_SEGURO_2.pdf [pdf - 1.64 MB]\" size=\"1.64 MB\" id=\"link_1\">{{context_path}}/content/resources/20260502203829207VJ7/GUIA_DEL_ECOMENSAJERO_SEGURO_2.pdf</a><span id=\"info_file_1\" class=\"exe-link-data file-size\">(pdf - 1.64 <abbr title=\"MegaBytes\">MB</abbr> )</span></p>\n<p><br></p><p class=\"clearfix\"></p></div>\n            </div></div></div>","jsonProperties":"{\"ideviceId\":\"20260502203829207VJ7\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>\\\"Para ser un buen Ecomensajero, primero debemos saber navegar seguros\\\"</p>\\n<p><a href=\\\"{{context_path}}/content/resources/20260502203829207VJ7/GUIA_DEL_ECOMENSAJERO_SEGURO_2.pdf\\\" title=\\\"GUIA_DEL_ECOMENSAJERO_SEGURO_2.pdf [pdf - 1.64 MB]\\\" size=\\\"1.64 MB\\\" id=\\\"link_1\\\">{{context_path}}/content/resources/20260502203829207VJ7/GUIA_DEL_ECOMENSAJERO_SEGURO_2.pdf</a><span id=\\\"info_file_1\\\" class=\\\"exe-link-data file-size\\\">(pdf - 1.64 <abbr title=\\\"MegaBytes\\\">MB</abbr> )</span></p>\\n<p><br /></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"20260502214002NVLBJN":{"name":"Nuestra misión: la infografía interactiva.","order":6,"idevices":{"20260502205241060101":{"order":1,"htmlView":"<div class=\"exe-text-template\"><div class=\"textIdeviceContent\">\n            <div class=\"exe-text-activity\">\n                <div><p><strong>El producto</strong>: cada equipo de Ecomensajeros diseñará una infografía interactiva sobre un ecosistema andaluz.&nbsp;&nbsp;</p>\n<p><strong>El objetivo</strong>: sintetizar toda la información que habéis investigado en un formato visual que sea atractivo y fácil de entender para los demás.</p>\n<p><strong>El toque mágico</strong>: no será un simple dibujo; vuestra infografía tendrá elementos interactivos&nbsp; y un código QR para que cualquier persona pueda ver vuestro trabajo desde su móvil.</p>\n<p><strong>Canva</strong>: es nuestra herramienta de diseño. Nos permite mezclar textos, fotos de animales, iconos de plantas y videos de un solo lugar de forma muy creativa. Al estar en la nube, podéis trabajar en equipo desde los portátiles del colegio.&nbsp;</p>\n<p><strong>Generador de códigos QR</strong>: con él, daremos el salto del mundo digital al mundo físico, pegando vuestros trabajos por el centro para que toda la comunidad educativa los disfrute.</p>\n<p>Hemos elegido estas herramientas porque ofrecen diseños claros y diferentes tipologías de letras, facilitando así la lectura. Además, el código QR, permite que cualquier persona, sin importar como acceda a la información, pueda disfrutar de vuestro conocimiento.</p><p class=\"clearfix\"></p></div>\n            </div></div></div>","jsonProperties":"{\"ideviceId\":\"20260502205241060101\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p><strong>El producto</strong>: cada equipo de Ecomensajeros diseñará una infografía interactiva sobre un ecosistema andaluz.  </p>\\n<p><strong>El objetivo</strong>: sintetizar toda la información que habéis investigado en un formato visual que sea atractivo y fácil de entender para los demás.</p>\\n<p><strong>El toque mágico</strong>: no será un simple dibujo; vuestra infografía tendrá elementos interactivos  y un código QR para que cualquier persona pueda ver vuestro trabajo desde su móvil.</p>\\n<p><strong>Canva</strong>: es nuestra herramienta de diseño. Nos permite mezclar textos, fotos de animales, iconos de plantas y videos de un solo lugar de forma muy creativa. Al estar en la nube, podéis trabajar en equipo desde los portátiles del colegio. </p>\\n<p><strong>Generador de códigos QR</strong>: con él, daremos el salto del mundo digital al mundo físico, pegando vuestros trabajos por el centro para que toda la comunidad educativa los disfrute.</p>\\n<p>Hemos elegido estas herramientas porque ofrecen diseños claros y diferentes tipologías de letras, facilitando así la lectura. Además, el código QR, permite que cualquier persona, sin importar como acceda a la información, pueda disfrutar de vuestro conocimiento.</p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"20260502214002WSBUQO":{"name":"NUESTRA BIBLIOTECA DIGITAL.","order":7,"idevices":{"2026050221071621368G":{"order":1,"htmlView":"<div class=\"exe-text-template\"><div class=\"textIdeviceContent\">\n            <div class=\"exe-text-activity\">\n                <div><p><strong>Ecomensajeros</strong>: Aquí teneis vuestro muro de investigación. He seleccionado los mejores videos, fotos y artículos sobre ecosistemas andaluces para que realices unas excelentes infografías.</p>\n<p><a href=\"{{context_path}}/content/resources/2026050221071621368G/PADLET.pdf\" title=\"PADLET.pdf\" size=\"18.62 KB\" id=\"link_2\">{{context_path}}/content/resources/2026050221071621368G/PADLET.pdf</a></p>\n<p>Padlet permite una navegación sencilla y visual, ideal para que el alumnado de 4º identifique rápidamente la información relevante.&nbsp;</p>\n<p><strong>Espacio Docente</strong>: en mi espacio como docente he utilizado la herramienta Symbaloo, me facilita tener todas las herramientas a un solo clic, optimizando el tiempo en el aula.</p>\n<p><a href=\"{{context_path}}/content/resources/2026050221071621368G/Symbaloo.pdf\" title=\"Symbaloo.pdf\" size=\"17.61 KB\" id=\"link_3\">{{context_path}}/content/resources/2026050221071621368G/Symbaloo.pdf</a></p><p class=\"clearfix\"></p></div>\n            </div></div></div>","jsonProperties":"{\"ideviceId\":\"2026050221071621368G\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p><strong>Ecomensajeros</strong>: Aquí teneis vuestro muro de investigación. He seleccionado los mejores videos, fotos y artículos sobre ecosistemas andaluces para que realices unas excelentes infografías.</p>\\n<p><a href=\\\"{{context_path}}/content/resources/2026050221071621368G/PADLET.pdf\\\" title=\\\"PADLET.pdf\\\" size=\\\"18.62 KB\\\" id=\\\"link_2\\\">{{context_path}}/content/resources/2026050221071621368G/PADLET.pdf</a></p>\\n<p>Padlet permite una navegación sencilla y visual, ideal para que el alumnado de 4º identifique rápidamente la información relevante. </p>\\n<p><strong>Espacio Docente</strong>: en mi espacio como docente he utilizado la herramienta Symbaloo, me facilita tener todas las herramientas a un solo clic, optimizando el tiempo en el aula.</p>\\n<p><a href=\\\"{{context_path}}/content/resources/2026050221071621368G/Symbaloo.pdf\\\" title=\\\"Symbaloo.pdf\\\" size=\\\"17.61 KB\\\" id=\\\"link_3\\\">{{context_path}}/content/resources/2026050221071621368G/Symbaloo.pdf</a></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"20260502214002YIKPEL":{"name":"¿CÚANDO LO HACEMOS?","order":8,"idevices":{"20260502214210442QKX":{"order":1,"htmlView":"<div class=\"exe-text-template\"><div class=\"textIdeviceContent\">\n            <div class=\"exe-text-activity\">\n                <div><p><a href=\"{{context_path}}/content/resources/20260502214210442QKX/Lnea_del_tiempo_Ecomensajeros_Andaluces..png\" title=\"Lnea_del_tiempo_Ecomensajeros_Andaluces..png\" size=\"512.44 KB\" id=\"link_4\">{{context_path}}/content/resources/20260502214210442QKX/Lnea_del_tiempo_Ecomensajeros_Andaluces..png</a></p>\n<p>Línea del tiempo de la SdA \"Ecomensajeros Andaluces\" dividida en 4 fases y 6 sesiones:&nbsp;</p>\n<p><strong>Fase 1</strong>. Investigación (Sesiones 1-2).</p>\n<p><strong>Tarea</strong>: Selección del Ecosistema Andaluz (Doñana, Sierra Nevada, Marismas, etc. y búsqueda de información crítica.</p>\n<p><strong>Agrupamiento</strong>: grupos cooperativos de 4 personas: portavoz, secretario, coordinador y controlador).</p>\n<p><strong>Herramientas</strong>: buscadores seguros y conexión a internet.</p>\n<p><strong>Fase 2.</strong> Diseño en Canva. (Sesiones 3-4).</p>\n<p><strong>Tarea</strong>: Volcar la información en una plantilla de Canva, síntesis de texto,&nbsp; elección de iconos y carga de imágenes/vídeos.</p>\n<p><strong>Estrategia digital</strong>: Uso responsable de imágenes con licencias Creative Commons.</p>\n<p><strong>Espacio</strong>:&nbsp; Aula con portátiles.</p>\n<p><strong>Fase 3:</strong> Interactividad y código QR. (Sesión 5).</p>\n<p><strong>Tarea</strong>: Finalizar el diseño e instalar enlaces interactivos. Generar el código QR que enlace al producto final.</p>\n<p><strong>Gestión de la incertidumbre</strong>: Aplicaremos un plan B en caso de fallo de la red ( descarga del diseño en PDF para visualización offline ).</p>\n<p><strong>Agrupamiento</strong>: parejas de revisión ( un grupo revisa el trabajo del otro ).</p>\n<p><strong>Fase 4</strong>: difusión y exposición. (Sesión 6).</p>\n<p><strong>Tarea</strong>: Impresión de carteles y colocación en puntos estratégicos del centro con una breve presentación oral.</p>\n<p><strong>Producto final</strong>: \"Ruta de los Ecosistemas\" en los pasillos del centro para toda la comunidad educativa.&nbsp;</p>\n<p><strong>Recursos:</strong> Dispositivos móviles para escanear los QR y comprobar el funcionamiento.</p><p class=\"clearfix\"></p></div>\n            </div></div></div>","jsonProperties":"{\"ideviceId\":\"20260502214210442QKX\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p><a href=\\\"{{context_path}}/content/resources/20260502214210442QKX/Lnea_del_tiempo_Ecomensajeros_Andaluces..png\\\" title=\\\"Lnea_del_tiempo_Ecomensajeros_Andaluces..png\\\" size=\\\"512.44 KB\\\" id=\\\"link_4\\\">{{context_path}}/content/resources/20260502214210442QKX/Lnea_del_tiempo_Ecomensajeros_Andaluces..png</a></p>\\n<p>Línea del tiempo de la SdA \\\"Ecomensajeros Andaluces\\\" dividida en 4 fases y 6 sesiones: </p>\\n<p><strong>Fase 1</strong>. Investigación (Sesiones 1-2).</p>\\n<p><strong>Tarea</strong>: Selección del Ecosistema Andaluz (Doñana, Sierra Nevada, Marismas, etc. y búsqueda de información crítica.</p>\\n<p><strong>Agrupamiento</strong>: grupos cooperativos de 4 personas: portavoz, secretario, coordinador y controlador).</p>\\n<p><strong>Herramientas</strong>: buscadores seguros y conexión a internet.</p>\\n<p><strong>Fase 2.</strong> Diseño en Canva. (Sesiones 3-4).</p>\\n<p><strong>Tarea</strong>: Volcar la información en una plantilla de Canva, síntesis de texto,  elección de iconos y carga de imágenes/vídeos.</p>\\n<p><strong>Estrategia digital</strong>: Uso responsable de imágenes con licencias Creative Commons.</p>\\n<p><strong>Espacio</strong>:  Aula con portátiles.</p>\\n<p><strong>Fase 3:</strong> Interactividad y código QR. (Sesión 5).</p>\\n<p><strong>Tarea</strong>: Finalizar el diseño e instalar enlaces interactivos. Generar el código QR que enlace al producto final.</p>\\n<p><strong>Gestión de la incertidumbre</strong>: Aplicaremos un plan B en caso de fallo de la red ( descarga del diseño en PDF para visualización offline ).</p>\\n<p><strong>Agrupamiento</strong>: parejas de revisión ( un grupo revisa el trabajo del otro ).</p>\\n<p><strong>Fase 4</strong>: difusión y exposición. (Sesión 6).</p>\\n<p><strong>Tarea</strong>: Impresión de carteles y colocación en puntos estratégicos del centro con una breve presentación oral.</p>\\n<p><strong>Producto final</strong>: \\\"Ruta de los Ecosistemas\\\" en los pasillos del centro para toda la comunidad educativa. </p>\\n<p><strong>Recursos:</strong> Dispositivos móviles para escanear los QR y comprobar el funcionamiento.</p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"20260502214002CPLLUO":{"name":"¿CÓMO MEDIREMOS NUESTRO ÉXITO?","order":9,"idevices":{"20260502220257968FZO":{"order":1,"htmlView":"<div class=\"exe-text-template\"><div class=\"textIdeviceContent\">\n            <div class=\"exe-text-activity\">\n                <div><p>En esta sección, relacionamos lo que hacemos en clase&nbsp; con lo que debemos de aprender (Criterios de Evaluación). <a href=\"{{context_path}}/content/resources/20260502220257968FZO/Asociamos_tareas_a_Criterios_de_evaluacin_.pdf\" title=\"Asociamos_tareas_a_Criterios_de_evaluacin_.pdf\" size=\"110.76 KB\" id=\"link_5\">{{context_path}}/content/resources/20260502220257968FZO/Asociamos_tareas_a_Criterios_de_evaluacin_.pdf</a></p>\n<p></p><p class=\"clearfix\"></p></div>\n            </div></div></div>","jsonProperties":"{\"ideviceId\":\"20260502220257968FZO\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>En esta sección, relacionamos lo que hacemos en clase  con lo que debemos de aprender (Criterios de Evaluación). <a href=\\\"{{context_path}}/content/resources/20260502220257968FZO/Asociamos_tareas_a_Criterios_de_evaluacin_.pdf\\\" title=\\\"Asociamos_tareas_a_Criterios_de_evaluacin_.pdf\\\" size=\\\"110.76 KB\\\" id=\\\"link_5\\\">{{context_path}}/content/resources/20260502220257968FZO/Asociamos_tareas_a_Criterios_de_evaluacin_.pdf</a></p>\\n<p></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"20260502214002TIFSYF":{"name":"MIS HERRAMIENTAS DE EVALUACIÓN.","order":10,"idevices":{"20260502222013467LJC":{"order":1,"htmlView":"<div class=\"exe-text-template\"><div class=\"textIdeviceContent\">\n            <div class=\"exe-text-activity\">\n                <div><p>Esta SdA utiliza utiliza tres mecanismos para obtener una imagen real del aprendizaje:&nbsp;</p>\n<p><strong>autoevaluación/coevaluación, evaluación docente y observación directa.</strong></p>\n<p><strong>1. Diana de Evaluación (Autoevaluación/coevaluación).&nbsp;</strong></p>\n<p>Se aplica en la sesión 5 para evaluar la capacidad de trabajo colaborativo y respeto.</p>\n<p>Netiqueta: desde mensajes neutros (Nivel 1) hasta liderazgo positivo y motivador (Nivel 4).</p>\n<p>Colaboración: desde trabajo individual (Nivel 1) hasta hasta facilitar el trabajo de los demás (Nivel 4).</p>\n<p>Respeto a la Autoría. Desde no citar fuentes (Nivel 1) hasta la atribución perfecta de recursos.&nbsp;</p>\n<p><strong>2. Rúbrica Analítica</strong> en la Sesión 6 para evaluar la calidad técnica de la Infografía y el Código QR.</p>\n<p><a href=\"{{context_path}}/content/resources/20260502222013467LJC/INSTRUMENTOS_DE_EVALUACIN_SdA_Ecomensajeros_Andaluces.pdf\" title=\"INSTRUMENTOS_DE_EVALUACIN_SdA_Ecomensajeros_Andaluces.pdf\" size=\"126.04 KB\" id=\"link_6\">{{context_path}}/content/resources/20260502222013467LJC/INSTRUMENTOS_DE_EVALUACIN_SdA_Ecomensajeros_Andaluces.pdf</a></p>\n<p><strong>3. Registro de Observación.</strong>&nbsp;</p>\n<p>Durante las sesiónes 3 a 5, se utilizar una App para anotar evidencias de respeto y resolución técnicos de forma cualitativa.&nbsp;</p>\n<p>Para garantizar que nada detenga nuestro aprendizaje, aplicaremos estos tres niveles:</p>\n<p><strong>1. Ayudante TIC</strong>: un alumno/a experto por equipo para ayudar a sus compañeros.</p>\n<p><strong>2. Plan B</strong> (analógico) por si falla internet.</p>\n<p><strong>3. Banco de recursos local</strong>: tutoriales y materiales descargados previamente en los equipos.</p><p class=\"clearfix\"></p></div>\n            </div></div></div>","jsonProperties":"{\"ideviceId\":\"20260502222013467LJC\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>Esta SdA utiliza utiliza tres mecanismos para obtener una imagen real del aprendizaje: </p>\\n<p><strong>autoevaluación/coevaluación, evaluación docente y observación directa.</strong></p>\\n<p><strong>1. Diana de Evaluación (Autoevaluación/coevaluación). </strong></p>\\n<p>Se aplica en la sesión 5 para evaluar la capacidad de trabajo colaborativo y respeto.</p>\\n<p>Netiqueta: desde mensajes neutros (Nivel 1) hasta liderazgo positivo y motivador (Nivel 4).</p>\\n<p>Colaboración: desde trabajo individual (Nivel 1) hasta hasta facilitar el trabajo de los demás (Nivel 4).</p>\\n<p>Respeto a la Autoría. Desde no citar fuentes (Nivel 1) hasta la atribución perfecta de recursos. </p>\\n<p><strong>2. Rúbrica Analítica</strong> en la Sesión 6 para evaluar la calidad técnica de la Infografía y el Código QR.</p>\\n<p><a href=\\\"{{context_path}}/content/resources/20260502222013467LJC/INSTRUMENTOS_DE_EVALUACIN_SdA_Ecomensajeros_Andaluces.pdf\\\" title=\\\"INSTRUMENTOS_DE_EVALUACIN_SdA_Ecomensajeros_Andaluces.pdf\\\" size=\\\"126.04 KB\\\" id=\\\"link_6\\\">{{context_path}}/content/resources/20260502222013467LJC/INSTRUMENTOS_DE_EVALUACIN_SdA_Ecomensajeros_Andaluces.pdf</a></p>\\n<p><strong>3. Registro de Observación.</strong> </p>\\n<p>Durante las sesiónes 3 a 5, se utilizar una App para anotar evidencias de respeto y resolución técnicos de forma cualitativa. </p>\\n<p>Para garantizar que nada detenga nuestro aprendizaje, aplicaremos estos tres niveles:</p>\\n<p><strong>1. Ayudante TIC</strong>: un alumno/a experto por equipo para ayudar a sus compañeros.</p>\\n<p><strong>2. Plan B</strong> (analógico) por si falla internet.</p>\\n<p><strong>3. Banco de recursos local</strong>: tutoriales y materiales descargados previamente en los equipos.</p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"20260502214002AQLBBP":{"name":"GUÍA DIDÁCTICA.","order":11,"idevices":{"20260502224919896IBW":{"order":1,"htmlView":"<div class=\"exe-text-template\"><div class=\"textIdeviceContent\">\n            <div class=\"exe-text-activity\">\n                <div><p><strong>1. INTRODUCCIÓN Y CONTEXTUALIZACIÓN.</strong></p>\n<p>Esta SdA titulada<strong> \"Ecomensajeros Andaluces\"</strong> esta diseñada para el alumnado de 4º de Primaria dentro del área de Conocimiento del Medio. El objetivo central es que el alumnado investigue los ecosistemas de nuestra comunidad y los divulgue mediante un producto digital interactivo:<strong> Infografía en Canva y Código QR.</strong></p>\n<p><strong>2. RELACIÓN DE TAREAS Y CRITERIOS DE EVALUACIÓN.</strong></p>\n<p>Para la implementación de este proyecto, se han vinculado las actividades con los siguientes criterios de evaluación.</p>\n<p>La actividad/tarea de investigadores del ecosistema: búsqueda en webs sobre la flora y la fauna, se ha vinculado con el criterio CE. 2.1. Buscar, seleccionar y contrastar información de diferentes fuentes.</p>\n<p>La actividad/tarea de taller de diseño Ecomensajero: creación de la infografía en Canva se ha vinculado con el criterio CE. 3.3. crear productos sencillos utilizando herramientas digitales de forma segura y responsable.</p>\n<p>Revisión y Netiqueta: verificación del respeto a la autoría y el uso de mensajes positivos se ha&nbsp; vinculado con el criterio CE. 3.1. utilizar herramientas o plataformas para comunicarse y trabajar de manera colaborativa.</p>\n<p>Lanzamiento del QR: generación del código y montaje del panel informativo se ha vinculado con el criterio CE. 3.3. fomentando el uso sostenible de las herramientas digitales.&nbsp;</p>\n<p><strong>3. METODOLOGÍA Y ATENCIÓN A LA DIVERSIDAD (DUA).</strong></p>\n<p>Para asegurar que todo el alumnado alcance los objetivos, se proponen las siguientes pautas:</p>\n<p><strong>- Gestión de la Incertidumbre Digital:</strong></p>\n<p>Se establece un protocolo de tres niveles para resolver problemas técnicos: <strong>la figura del ayudante TIC, un plan B y un banco de recursos.</strong></p>\n<p><strong>- Evaluación formativa:&nbsp;</strong></p>\n<p>El proceso no busca solo una nota, sino entender como aprende cada alumno mediante el uso combinado de una <strong>Diana de Evaluación</strong> (autoevaluación) y una<strong> Rúbrica</strong> de producto final.</p>\n<p><strong>4. Recomendaciones para el Docente.</strong></p>\n<p><strong>- Rol facilitador:</strong> el docente debe actuar como guía, permitiendo que el alumnado gane autonomía y cuidando la calidad del contenido y la creatividad.</p>\n<p><strong>- Seguridad: </strong>es fundamental realizar la sesión sobre protección de datos antes de iniciar el trabajo en la nube para gestionar correctamente la identidad del alumnado.&nbsp;</p>\n<p></p><p class=\"clearfix\"></p></div>\n            </div></div></div>","jsonProperties":"{\"ideviceId\":\"20260502224919896IBW\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p><strong>1. INTRODUCCIÓN Y CONTEXTUALIZACIÓN.</strong></p>\\n<p>Esta SdA titulada<strong> \\\"Ecomensajeros Andaluces\\\"</strong> esta diseñada para el alumnado de 4º de Primaria dentro del área de Conocimiento del Medio. El objetivo central es que el alumnado investigue los ecosistemas de nuestra comunidad y los divulgue mediante un producto digital interactivo:<strong> Infografía en Canva y Código QR.</strong></p>\\n<p><strong>2. RELACIÓN DE TAREAS Y CRITERIOS DE EVALUACIÓN.</strong></p>\\n<p>Para la implementación de este proyecto, se han vinculado las actividades con los siguientes criterios de evaluación.</p>\\n<p>La actividad/tarea de investigadores del ecosistema: búsqueda en webs sobre la flora y la fauna, se ha vinculado con el criterio CE. 2.1. Buscar, seleccionar y contrastar información de diferentes fuentes.</p>\\n<p>La actividad/tarea de taller de diseño Ecomensajero: creación de la infografía en Canva se ha vinculado con el criterio CE. 3.3. crear productos sencillos utilizando herramientas digitales de forma segura y responsable.</p>\\n<p>Revisión y Netiqueta: verificación del respeto a la autoría y el uso de mensajes positivos se ha  vinculado con el criterio CE. 3.1. utilizar herramientas o plataformas para comunicarse y trabajar de manera colaborativa.</p>\\n<p>Lanzamiento del QR: generación del código y montaje del panel informativo se ha vinculado con el criterio CE. 3.3. fomentando el uso sostenible de las herramientas digitales. </p>\\n<p><strong>3. METODOLOGÍA Y ATENCIÓN A LA DIVERSIDAD (DUA).</strong></p>\\n<p>Para asegurar que todo el alumnado alcance los objetivos, se proponen las siguientes pautas:</p>\\n<p><strong>- Gestión de la Incertidumbre Digital:</strong></p>\\n<p>Se establece un protocolo de tres niveles para resolver problemas técnicos: <strong>la figura del ayudante TIC, un plan B y un banco de recursos.</strong></p>\\n<p><strong>- Evaluación formativa: </strong></p>\\n<p>El proceso no busca solo una nota, sino entender como aprende cada alumno mediante el uso combinado de una <strong>Diana de Evaluación</strong> (autoevaluación) y una<strong> Rúbrica</strong> de producto final.</p>\\n<p><strong>4. Recomendaciones para el Docente.</strong></p>\\n<p><strong>- Rol facilitador:</strong> el docente debe actuar como guía, permitiendo que el alumnado gane autonomía y cuidando la calidad del contenido y la creatividad.</p>\\n<p><strong>- Seguridad: </strong>es fundamental realizar la sesión sobre protección de datos antes de iniciar el trabajo en la nube para gestionar correctamente la identidad del alumnado. </p>\\n<p></p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}},"block-1777760195834-dcsww4luh":{"name":"CREDITOS Y DESCARGA.","order":11,"idevices":{"idevice-1777760195831-zecbx2uk6":{"order":1,"htmlView":"<div class=\"exe-text-template\">\n    <p>Autoría y Licencia:</p>\n<p>Proyecto: Ecomensajeros Andaluces.</p>\n<p>Autora: María José Cruz Herrera.</p>\n<p>Licencia: Este material se publica bajo la licencia CC BY- SA 4.0. Esto significa que puedes compartir, copiar y redistribuir el material en cualquier medio o formato, siempre que se reconozca la autoría y se mantenga la misma licencia.</p>\n</div>","jsonProperties":"{\"ideviceId\":\"idevice-1777760195831-zecbx2uk6\",\"textInfoDurationInput\":\"\",\"textInfoDurationTextInput\":\"Duración\",\"textInfoParticipantsInput\":\"\",\"textInfoParticipantsTextInput\":\"Agrupamiento\",\"textTextarea\":\"<p>Autoría y Licencia:</p>\\n<p>Proyecto: Ecomensajeros Andaluces.</p>\\n<p>Autora: María José Cruz Herrera.</p>\\n<p>Licencia: Este material se publica bajo la licencia CC BY- SA 4.0. Esto significa que puedes compartir, copiar y redistribuir el material en cualquier medio o formato, siempre que se reconozca la autoría y se mantenga la misma licencia.</p>\",\"textFeedbackInput\":\"Mostrar retroalimentación\",\"textFeedbackTextarea\":\"\"}"}}}}}};